        src: string,
        zipFilePath: string | undefined,
        zipAFolderOptions?: ZipAFolderOptions
    ): Promise<void | Error> {
           const o: ZipAFolderOptions = zipAFolderOptions || {};


        if (o.compression === COMPRESSION_LEVEL.uncompressed) {
            <PLACEHOLDER>
                src,
